import { describe, expect, it, vi } from 'vitest'
import { page, userEvent } from 'vitest/browser'
import { defineComponent, useTemplateRef, onMounted } from 'vue'
import { onClickOutside } from './index'

function getComplexComponent(useGetter = false) {
  return defineComponent({
    template: `
    <div>
      <div ref="target">
        Inside
      </div>

      <div ref="outside">
        Outside
        <label>
          <input type="radio"/>
          <span>Label</span>
        </label>
      </div>

      <div>
        Other
      </div>
   </div>
  `,
    setup() {
      const target = useTemplateRef<HTMLDivElement>('target')
      const outside = useTemplateRef<HTMLDivElement>('outside')
      onClickOutside(
        useGetter ? () => target.value : target,
        (...args) => {
          console.log(...args)
        },
        {
          ignore: [outside],
        },
      )

      return {
        target,
        outside,
      }
    },
  })
}

describe('onClickOutside', () => {
  it('should work with ignored element', async () => {
    const consoleSpy = vi.spyOn(console, 'log').mockImplementation(() => {})
    const screen = page.render(getComplexComponent())
    const target = screen.getByText('Inside')
    const outside = screen.getByText('Outside')
    const label = screen.getByText('Label')
    const other = screen.getByText('Other')

    await expect.element(target).toBeInTheDocument()
    await expect.element(outside).toBeInTheDocument()
    expect(consoleSpy).not.toHaveBeenCalled()
    await userEvent.click(outside)
    expect(consoleSpy).not.toHaveBeenCalled()
    await userEvent.click(label)
    expect(consoleSpy).not.toHaveBeenCalled()
    await userEvent.click(other)
    expect(consoleSpy).toHaveBeenCalled()
  })

  it('allow the value of target to be a getter', async () => {
    const consoleSpy = vi.spyOn(console, 'log').mockImplementation(() => {})
    const screen = page.render(getComplexComponent(true))
    const target = screen.getByText('Inside')
    const other = screen.getByText('Other')

    await expect.element(target).toBeInTheDocument()
    await expect.element(other).toBeInTheDocument()
    expect(consoleSpy).not.toHaveBeenCalled()
    await userEvent.click(target)
    expect(consoleSpy).not.toHaveBeenCalled()
    await userEvent.click(other)
    expect(consoleSpy).toHaveBeenCalled()
  })

  it('should detect iframe clicks inside shadow DOM with detectIframe option', async () => {
    const handlerSpy = vi.fn()

    const CustomElApp = defineComponent({
      template: `
        <div>
          <div ref="target">
            Inside
          </div>
          <div ref="shadowHost">
          </div>
        </div>
      `,
      setup() {
        const target = useTemplateRef<HTMLDivElement>('target')
        const shadowHost = useTemplateRef<HTMLDivElement>('shadowHost')

        onClickOutside(target, handlerSpy, {
          detectIframe: true,
        })

        onMounted(() => {
          const host = shadowHost.value!
          const shadowRoot = host.attachShadow({ mode: 'open' })
          shadowRoot.innerHTML = '<iframe tabindex="0"></iframe>'
        })

        return { target, shadowHost }
      },
    })

    const screen = page.render(CustomElApp)
    const target = screen.getByText('Inside')

    await expect.element(target).toBeInTheDocument()

    expect(handlerSpy).not.toHaveBeenCalled()

    // Focus the iframe inside the shadow DOM.
    // When clicking an iframe inside a shadow DOM in a real browser:
    // - The window blur event fires
    // - document.activeElement becomes the shadow host
    // - shadowHost.shadowRoot.activeElement becomes the iframe
    const shadowHost = document.querySelector<HTMLDivElement>('[ref="shadowHost"]')
    const shadowIframe = shadowHost?.shadowRoot?.querySelector<HTMLIFrameElement>('iframe')
    expect(shadowIframe).toBeTruthy()
    shadowIframe!.focus()

    // Now document.activeElement should be the shadow host
    // and shadowHost.shadowRoot.activeElement should be the iframe
    expect(document.activeElement).toBe(shadowHost)

    // Simulate the window blur event
    window.dispatchEvent(new FocusEvent('blur'))

    // The blur handler uses setTimeout(0), so we need to wait
    await new Promise(resolve => setTimeout(resolve, 10))

    expect(handlerSpy).toHaveBeenCalled()
  })

  it('should not trigger blur handler if iframe is inside the target element', async () => {
    const handlerSpy = vi.fn()

    const App = defineComponent({
      template: `
        <div>
          <div ref="target">
            <iframe></iframe>
          </div>
        </div>
      `,
      setup() {
        const target = useTemplateRef<HTMLDivElement>('target')

        onClickOutside(target, handlerSpy, {
          detectIframe: true,
        })

        return { target }
      },
    })

    const screen = page.render(App)

    expect(handlerSpy).not.toHaveBeenCalled()

    // Simulate blur event — but the iframe is inside the target, so handler should NOT be called
    window.dispatchEvent(new FocusEvent('blur'))
    await new Promise(resolve => setTimeout(resolve, 10))

    expect(handlerSpy).not.toHaveBeenCalled()
  })
})
